"use client";

import React, { useRef, useLayoutEffect } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

export function HorizontalScroll({ children }: { children: React.ReactNode }) {
  const sectionRef = useRef<HTMLDivElement>(null);
  const triggerRef = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    const section = sectionRef.current;
    const trigger = triggerRef.current;
    if (!section || !trigger) return;

    const totalWidth = section.scrollWidth - window.innerWidth;

    const pin = gsap.to(section, {
      x: -totalWidth,
      ease: 'none',
      scrollTrigger: {
        trigger: trigger,
        pin: true,
        scrub: 1,
        start: 'top top',
        end: () => `+=${section.scrollWidth}`,
        invalidateOnRefresh: true,
      },
    });

    return () => {
      pin.kill();
    };
  }, []);

  return (
    <div ref={triggerRef} className="overflow-hidden bg-background">
      <div ref={sectionRef} className="flex flex-nowrap h-screen items-center px-12 gap-12 w-fit">
        {children}
      </div>
    </div>
  );
}
